import numpy as np
import time

class LazyOuterNdarray(np.ndarray):
    def __new__(cls, a, b):
        # np.ndarray.__new__ allocates memory
        obj = np.ndarray.__new__(cls, (len(a), len(b)), dtype=a.dtype)
        obj.a = a
        obj.b = b
        obj._computed = False
        return obj

    def _compute(self):
        if not self._computed:
            np.copyto(self, self.a[:, None] * self.b)
            self._computed = True

    def __sub__(self, other):
        self._compute()
        return super().__sub__(other)

